1135	    pub fn set_top(&mut self, idx: impl Into<StackIdxConv>) {
1136	        let new_top: StackIdx = idx.into().0;
1137	        let new_top_u = new_top.0 as usize;
1138	        let cur = self.top.0 as usize;
1139	        if new_top_u > cur {
1140	            let existing_end = self.stack.len().min(new_top_u);
1141	            for i in cur..existing_end {
1142	                self.stack[i] = StackValue::default();
1143	            }
1144	            if new_top_u > self.stack.len() {
1145	                self.stack.resize_with(new_top_u, StackValue::default);
1146	            }
1147	        }
1148	        self.top = new_top;
1149	    }
